// SETUP: Copy all images from the bolt/ folder into frontend/public/posters/
// Posters: Avatar.jpg, Mad Max Fury Road.jpg, apocolypto.jpg,
//          forrest gump.jpg, Life of Pi.jpg, Interstellar.jpg
// Banners: avatar_theme.jpg, mad_max_fury_road_theme.jpg, apocolypto_theme.jpg,
//          forrestgump_theme.jpg, life_of_pi_theme.jpg, interstellar_theme.jpg

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './FilmFestival.css';

const films = [
  {
    id: 1,
    title: "Mad Max: Fury Road",
    year: 2015,
    director: "George Miller",
    poster: "/posters/Mad Max Fury Road.jpg",
    banner: "/posters/mad_max_fury_road_theme.jpg",
    theme: "Raw physical survival in a scorched post-apocalyptic wasteland.",
    description: "In a world stripped of civilization, every breath is a battle won. This visceral masterpiece captures survival in its most primal, relentless form.",
    screening: "December 15, 2024",
    time: "7:00 PM",
    price: "LKR 1,500",
    hall: "Main Auditorium",
    priceVal: 1500
  },
  {
    id: 2,
    title: "Avatar",
    year: 2009,
    director: "James Cameron",
    poster: "/posters/Avatar.jpg",
    banner: "/posters/avatar_theme.jpg",
    theme: "Cultural and ecological survival of an entire civilization.",
    description: "When a world's existence is threatened, survival transcends the individual. Avatar explores what it truly means to fight for a people, a land, and a way of life.",
    screening: "December 16, 2024",
    time: "6:30 PM",
    price: "LKR 1,800",
    hall: "Main Auditorium",
    priceVal: 1800
  },
  {
    id: 3,
    title: "Apocalypto",
    year: 2006,
    director: "Mel Gibson",
    poster: "/posters/apocolypto.jpg",
    banner: "/posters/apocolypto_theme.jpg",
    theme: "A father's desperate sprint for survival against impossible odds.",
    description: "Stripped of everything, one man's love for his family becomes his only weapon. Apocalypto is cinema's rawest portrait of instinct, fear, and the will to live.",
    screening: "December 17, 2024",
    time: "8:00 PM",
    price: "LKR 1,200",
    hall: "Screen 2",
    priceVal: 1200
  },
  {
    id: 4,
    title: "Forrest Gump",
    year: 1994,
    director: "Robert Zemeckis",
    poster: "/posters/forrest gump.jpg",
    banner: "/posters/forrestgump_theme.jpg",
    theme: "Emotional and psychological survival through life's greatest storms.",
    description: "Not all battles are fought with weapons. Forrest Gump reminds us that survival is often about the quiet strength to keep going when the world gives every reason to stop.",
    screening: "December 18, 2024",
    time: "5:00 PM",
    price: "LKR 1,000",
    hall: "Screen 2",
    priceVal: 1000
  },
  {
    id: 5,
    title: "Life of Pi",
    year: 2012,
    director: "Ang Lee",
    poster: "/posters/Life of Pi.jpg",
    banner: "/posters/life_of_pi_theme.jpg",
    theme: "Spiritual and physical survival alone on the open ocean.",
    description: "Adrift with only a tiger for company, Pi's journey is both a physical ordeal and a spiritual awakening. Life of Pi asks whether survival of the body is possible without survival of the soul.",
    screening: "December 19, 2024",
    time: "7:30 PM",
    price: "LKR 1,500",
    hall: "Main Auditorium",
    priceVal: 1500
  },
  {
    id: 6,
    title: "Interstellar",
    year: 2014,
    director: "Christopher Nolan",
    poster: "/posters/Interstellar.jpg",
    banner: "/posters/interstellar_theme.jpg",
    theme: "The survival of the entire human species across space and time.",
    description: "When Earth can no longer sustain us, love becomes the force that transcends physics. Interstellar elevates survival to a cosmic scale — the ultimate story of humanity refusing to be extinguished.",
    screening: "December 20, 2024",
    time: "9:00 PM",
    price: "LKR 2,000",
    hall: "Main Auditorium",
    priceVal: 2000
  }
];

function FilmFestival() {
  const [transactions, setTransactions] = useState([]);
  const [sessions, setSessions] = useState([]);
  const [loadingTx, setLoadingTx] = useState(false);
  const [loadingSessions, setLoadingSessions] = useState(false);
  const [errorTx, setErrorTx] = useState(null);
  const [errorSessions, setErrorSessions] = useState(null);

  // Booking Modal State
  const [selectedFilm, setSelectedFilm] = useState(null);
  const [bookingName, setBookingName] = useState('');
  const [bookingQty, setBookingQty] = useState(1);
  const [isBooked, setIsBooked] = useState(false);
  const [bookedTxId, setBookedTxId] = useState('');

  const fetchTransactions = async () => {
    setLoadingTx(true);
    setErrorTx(null);
    try {
      const response = await axios.get('http://localhost:8080/simulation/transactions');
      setTransactions(response.data || []);
    } catch (err) {
      console.error('Error fetching transactions:', err);
      setErrorTx('Failed to fetch transactions');
    } finally {
      setLoadingTx(false);
    }
  };

  const fetchSessions = async () => {
    setLoadingSessions(true);
    setErrorSessions(null);
    try {
      const response = await axios.get('http://localhost:8080/simulation/history');
      setSessions(response.data || []);
    } catch (err) {
      console.error('Error fetching session history:', err);
      setErrorSessions('Failed to fetch sessions');
    } finally {
      setLoadingSessions(false);
    }
  };

  useEffect(() => {
    fetchTransactions();
    fetchSessions();
  }, []);

  const handleBookNow = (film) => {
    setSelectedFilm(film);
    setBookingName('');
    setBookingQty(1);
    setIsBooked(false);
    setBookedTxId('');
  };

  const handleConfirmBooking = (e) => {
    e.preventDefault();
    if (!bookingName.trim()) return;

    // Generate random 8-char transaction id for frontend simulation confirmation
    const txId = Math.random().toString(36).substr(2, 9).toUpperCase();
    setBookedTxId(txId);
    setIsBooked(true);
  };

  const handleCloseModal = () => {
    setSelectedFilm(null);
    setIsBooked(false);
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return 'N/A';
    try {
      const d = new Date(dateStr);
      return d.toLocaleString('en-US', {
        month: 'short',
        day: 'numeric',
        hour: 'numeric',
        minute: '2-digit',
        hour12: true
      });
    } catch (e) {
      return dateStr;
    }
  };

  const scrollToFilms = () => {
    const el = document.getElementById('films');
    if (el) {
      el.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <div className="festival-container">
      {/* Cinematic Hero Section */}
      <section className="festival-hero" style={{ backgroundImage: 'url("/posters/interstellar_theme.jpg")' }}>
        <div className="hero-overlay"></div>
        <div className="hero-content">
          <div className="hero-badge">IIT Cultural Arts Society Presents</div>
          <h1 className="hero-title">SURVIVAL OF THE FITTEST</h1>
          <p className="hero-subtitle">Film Festival 2024</p>
          <div className="hero-divider"></div>
          <p className="hero-dates">📅 December 15–21, 2024 &nbsp;|&nbsp; 📍 Grand Cinema Complex, Colombo</p>
          <p className="hero-tagline">Six films. Six stories of survival. One unforgettable week.</p>
          <button className="hero-btn" onClick={scrollToFilms}>
            Explore Films <span className="arrow">↓</span>
          </button>
        </div>
      </section>

      {/* About Section */}
      <section className="festival-about">
        <div className="about-card">
          <h2 className="section-title-gold">About the Festival</h2>
          <p>
            The IIT Cultural Arts Society proudly presents this annual celebration of cinema's most powerful survival stories. 
            From post-apocalyptic wastelands to the vast ocean, from ancient civilizations to the edges of the universe — these 
            six films represent the pinnacle of human endurance portrayed on screen.
          </p>
          <p>
            Each screening is followed by an interactive panel discussion with film enthusiasts and academics exploring the survival 
            themes, artistic choices, and core emotional elements in each masterpiece. Join us to experience the power of the human spirit.
          </p>
        </div>
      </section>

      {/* Films Section */}
      <section className="festival-films" id="films">
        <h2 className="section-heading">
          Featured Films
          <span className="heading-underline"></span>
        </h2>

        <div className="films-grid">
          {films.map((film) => (
            <div className="film-card" key={film.id}>
              {/* Theme Banner Area */}
              <div 
                className="film-card-banner" 
                style={{ backgroundImage: `url("${film.banner}")` }}
              >
                <div className="banner-gradient"></div>
                <h3 className="banner-title">{film.title}</h3>
              </div>

              {/* Card Body */}
              <div className="film-card-body">
                <div className="film-card-flex">
                  <img src={film.poster} alt={`${film.title} Poster`} className="film-poster" />

                  <div className="film-details">
                    <p className="film-meta">🎬 {film.director} • 📅 {film.year}</p>
                    <p className="film-theme"><strong>Survival:</strong> {film.theme}</p>
                    <p className="film-description">{film.description}</p>
                  </div>
                </div>
              </div>

              {/* Card Footer */}
              <div className="film-card-footer">
                <div className="film-info-row">
                  <span className="info-item">📅 {film.screening}</span>
                  <span className="info-item">🕖 {film.time}</span>
                </div>
                <div className="film-info-row price-row">
                  <span className="hall-name">📍 {film.hall}</span>
                  <span className="ticket-price">{film.price}</span>
                </div>
                <button className="book-btn" onClick={() => handleBookNow(film)}>
                  BOOK NOW
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Database logs section */}
      <section className="festival-logs-section">
        <div className="logs-grid">
          {/* Ticket Transaction History */}
          <div className="log-panel">
            <div className="log-panel-header">
              <h3>Ticket Transaction History</h3>
              <button className="refresh-btn" onClick={fetchTransactions} disabled={loadingTx}>
                {loadingTx ? 'Refreshing...' : '🔄 Refresh'}
              </button>
            </div>

            <div className="table-responsive">
              <table className="log-table">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Transaction ID</th>
                    <th>Event Name</th>
                    <th>Customer</th>
                    <th>Price</th>
                    <th>Purchased At</th>
                  </tr>
                </thead>
                <tbody>
                  {errorTx && (
                    <tr>
                      <td colSpan="6" className="table-error">{errorTx}</td>
                    </tr>
                  )}
                  {transactions.length === 0 && !errorTx && (
                    <tr>
                      <td colSpan="6" className="table-empty">No transactions recorded yet.</td>
                    </tr>
                  )}
                  {transactions.slice(0, 20).map((tx, idx) => (
                    <tr key={tx.id}>
                      <td>{idx + 1}</td>
                      <td className="monospace-cell">{tx.transactionId ? `${tx.transactionId.substring(0, 8)}...` : 'N/A'}</td>
                      <td>{tx.eventName}</td>
                      <td>{tx.customerName}</td>
                      <td>LKR {tx.ticketPrice ? tx.ticketPrice.toLocaleString() : '0'}</td>
                      <td>{formatDate(tx.purchasedAt || tx.createdAt)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Session History */}
          <div className="log-panel">
            <div className="log-panel-header">
              <h3>Simulation Session History</h3>
              <button className="refresh-btn" onClick={fetchSessions} disabled={loadingSessions}>
                {loadingSessions ? 'Refreshing...' : '🔄 Refresh'}
              </button>
            </div>

            <div className="table-responsive">
              <table className="log-table">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Started At</th>
                    <th>Stopped At</th>
                    <th>Total Sold</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {errorSessions && (
                    <tr>
                      <td colSpan="5" className="table-error">{errorSessions}</td>
                    </tr>
                  )}
                  {sessions.length === 0 && !errorSessions && (
                    <tr>
                      <td colSpan="5" className="table-empty">No sessions recorded yet.</td>
                    </tr>
                  )}
                  {sessions.map((sess, idx) => (
                    <tr key={sess.id}>
                      <td>{idx + 1}</td>
                      <td>{formatDate(sess.startedAt)}</td>
                      <td>{sess.stoppedAt ? formatDate(sess.stoppedAt) : 'Active'}</td>
                      <td>{sess.totalTicketsSold}</td>
                      <td>
                        <span className={`status-badge ${sess.status === 'RUNNING' ? 'running' : 'stopped'}`}>
                          {sess.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </section>

      {/* Booking Modal */}
      {selectedFilm && (
        <div className="modal-backdrop" onClick={handleCloseModal}>
          <div className="booking-modal" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={handleCloseModal}>&times;</button>

            {!isBooked ? (
              <form onSubmit={handleConfirmBooking}>
                <h3 className="modal-title">Book Tickets</h3>
                <h4 className="modal-film-title">{selectedFilm.title}</h4>

                <div className="modal-body-content">
                  <div className="modal-img-container">
                    <img src={selectedFilm.poster} alt={selectedFilm.title} className="modal-poster" />
                  </div>

                  <div className="modal-fields">
                    <div className="info-badge-row">
                      <span className="modal-info-badge">📅 {selectedFilm.screening}</span>
                      <span className="modal-info-badge">🕖 {selectedFilm.time}</span>
                      <span className="modal-info-badge">📍 {selectedFilm.hall}</span>
                    </div>

                    <div className="form-group">
                      <label htmlFor="customerName">Full Name</label>
                      <input 
                        type="text" 
                        id="customerName" 
                        value={bookingName}
                        onChange={(e) => setBookingName(e.target.value)}
                        placeholder="Enter your name" 
                        required 
                      />
                    </div>

                    <div className="form-group qty-group">
                      <label>Number of Tickets</label>
                      <div className="qty-picker">
                        <button 
                          type="button" 
                          onClick={() => setBookingQty(prev => Math.max(1, prev - 1))}
                        >-</button>
                        <span>{bookingQty}</span>
                        <button 
                          type="button" 
                          onClick={() => setBookingQty(prev => prev + 1)}
                        >+</button>
                      </div>
                    </div>

                    <div className="total-display">
                      <span>Total Price:</span>
                      <span className="total-price-val">LKR {(selectedFilm.priceVal * bookingQty).toLocaleString()}</span>
                    </div>
                  </div>
                </div>

                <div className="modal-footer">
                  <button type="button" className="cancel-btn" onClick={handleCloseModal}>Cancel</button>
                  <button type="submit" className="confirm-btn">Confirm Booking</button>
                </div>
              </form>
            ) : (
              <div className="booking-success">
                <div className="success-icon">✓</div>
                <h3>Booking Confirmed!</h3>
                <p className="success-message">Thank you, <strong>{bookingName}</strong>. Your tickets have been reserved successfully.</p>

                <div className="ticket-receipt">
                  <p><strong>Film:</strong> {selectedFilm.title}</p>
                  <p><strong>Showtime:</strong> {selectedFilm.screening} at {selectedFilm.time}</p>
                  <p><strong>Hall:</strong> {selectedFilm.hall}</p>
                  <p><strong>Quantity:</strong> {bookingQty} ticket(s)</p>
                  <p><strong>Amount Paid:</strong> LKR {(selectedFilm.priceVal * bookingQty).toLocaleString()}</p>
                  <p className="receipt-tx"><strong>Transaction ID:</strong> <span className="mono">{bookedTxId}</span></p>
                </div>

                <button type="button" className="close-success-btn" onClick={handleCloseModal}>Dismiss</button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Page Footer */}
      <footer className="festival-footer">
        <p className="footer-society">IIT Cultural Arts Society</p>
        <p className="footer-location">Informatics Institute of Technology, Colombo 06, Sri Lanka</p>
        <p className="footer-copy">© 2024 Survival of the Fittest Film Festival. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default FilmFestival;
